{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMAMUfZQkzQ+3AcjirSOAIU"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"id":"SfOoowYsV-z-","executionInfo":{"status":"ok","timestamp":1773122652297,"user_tz":-180,"elapsed":39,"user":{"displayName":"Bassem Amin","userId":"03844483762484690298"}}},"outputs":[],"source":["\"\"\"\n","notification.py\n","----------------\n","Defines the Notification class for sending and managing\n","user notifications on the StreamFlix platform.\n","\n","Author: [Your Name]\n","Date: [Submission Date]\n","\"\"\"\n","\n","from datetime import datetime\n","\n","\n","class Notification:\n","    \"\"\"\n","    Represents a notification sent to a user.\n","\n","    Attributes:\n","        __notification_id (int): Unique notification identifier.\n","        __user (User): The recipient user.\n","        __message (str): Notification message.\n","        __notification_type (str): Type — 'Payment', 'Subscription', 'Content', 'General'.\n","        __timestamp (datetime): When the notification was created.\n","        __read_status (bool): Whether the user has read it.\n","    \"\"\"\n","\n","    _id_counter = 7000\n","    VALID_TYPES = ['Payment', 'Subscription', 'Content', 'General']\n","\n","    def __init__(self, user, message: str, notification_type: str = \"General\"):\n","        \"\"\"\n","        Create a new Notification.\n","\n","        Args:\n","            user (User): The recipient.\n","            message (str): The notification message.\n","            notification_type (str): One of the valid types. Default 'General'.\n","\n","        Raises:\n","            ValueError: If notification_type is invalid or message is empty.\n","        \"\"\"\n","        if notification_type not in Notification.VALID_TYPES:\n","            raise ValueError(f\"Type must be one of {Notification.VALID_TYPES}.\")\n","        if not message.strip():\n","            raise ValueError(\"Notification message cannot be empty.\")\n","\n","        Notification._id_counter += 1\n","        self.__notification_id = Notification._id_counter\n","        self.__user = user\n","        self.__message = message.strip()\n","        self.__notification_type = notification_type\n","        self.__timestamp = datetime.now()\n","        self.__read_status = False\n","        # Automatically add to user's notification list\n","        user.add_notification(self)\n","\n","    # ── Getters ──────────────────────────────────────────────\n","    def get_notification_id(self) -> int:\n","        \"\"\"Return the notification ID.\"\"\"\n","        return self.__notification_id\n","\n","    def get_message(self) -> str:\n","        \"\"\"Return the notification message.\"\"\"\n","        return self.__message\n","\n","    def get_type(self) -> str:\n","        \"\"\"Return the notification type.\"\"\"\n","        return self.__notification_type\n","\n","    def is_read(self) -> bool:\n","        \"\"\"Return True if the notification has been read.\"\"\"\n","        return self.__read_status\n","\n","    def mark_as_read(self) -> None:\n","        \"\"\"Mark the notification as read.\"\"\"\n","        self.__read_status = True\n","\n","    def get_details(self) -> dict:\n","        \"\"\"\n","        Return all notification details as a dictionary.\n","\n","        Returns:\n","            dict: Notification attributes.\n","        \"\"\"\n","        return {\n","            'notification_id': self.__notification_id,\n","            'user': self.__user.get_name(),\n","            'message': self.__message,\n","            'type': self.__notification_type,\n","            'timestamp': str(self.__timestamp),\n","            'read': self.__read_status\n","        }\n","\n","    def __str__(self) -> str:\n","        \"\"\"Return a formatted notification string.\"\"\"\n","        read_marker = \"Read\" if self.__read_status else \"Unread\"\n","        return (f\"[{self.__notification_type}] ({read_marker}) \"\n","                f\"To: {self.__user.get_name()} | {self.__message} \"\n","                f\"| {self.__timestamp.strftime('%Y-%m-%d %H:%M')}\")"]}]}